  | (string & {});

/**
 * Provider-specific settings for PixelArt image generation.
 */
export interface PixelArtImageSettings {
  /**
   * The size of the generated image, e.g. "512x512" or "1024x768".
   * When provided via providerOptions, this overrides the standard `size`
   * parameter.
   */
  size?: string;

  /**
   * The art style to apply to the generated image.
   * - "pixel": Classic pixel art style
   * - "retro": Retro-inspired pixel style with limited colour palette
   * - "8bit": Faithful 8-bit video-game aesthetic
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * The pixel density (pixels per unit) used during generation.
   * Higher values produce finer detail; lower values produce a blockier look.
   */
  pixelDensity?: number;
}

