export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  private async getArgs({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
  }: Parameters<ImageModelV3['doGenerate']>[0]) {
    const warnings: Array<SharedV3Warning> = [];

    // Parse provider-specific options (pixelart namespace)
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageSettingsSchema,
    });

    // Determine image size: provider option takes precedence, then standard
    // `size` parameter, then nothing (API default).
    const resolvedSize =
      pixelArtOptions?.size ?? size ?? undefined;

    // Aspect ratio is not natively supported; emit a warning if provided
    if (aspectRatio != null && size == null && pixelArtOptions?.size == null) {
      warnings.push({
        type: 'unsupported-setting',
        setting: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio directly. Use the `size` ' +
          'setting (e.g. "512x512") to control image dimensions.',
      });
    }

    const requestBody: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n: n ?? 1,
    };

    if (resolvedSize != null) requestBody.size = resolvedSize;
    if (seed != null) requestBody.seed = seed;
    if (pixelArtOptions?.style != null)
      requestBody.style = pixelArtOptions.style;
    if (pixelArtOptions?.pixelDensity != null)
      requestBody.pixel_density = pixelArtOptions.pixelDensity;

    return { requestBody, warnings } as const;
  }

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const { requestBody, warnings } = await this.getArgs(options);

    const currentDate =
      this.config._internal?.currentDate?.() ?? new Date();

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        options.headers,
      ),
      body: requestBody,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    // Download each image URL as binary data
    const images = await Promise.all(
      value.images.map(image =>
        this.downloadImage(image.url, options.abortSignal),
      ),
    );

    return {
      images,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: value.images.map(({ url, width, height }) => ({
            url,
            ...(width != null ? { width } : {}),
            ...(height != null ? { height } : {}),
          })),
          ...(value.model != null ? { model: value.model } : {}),
          ...(value.created_at != null ? { createdAt: value.created_at } : {}),
        },
      },
    };
  }

  private async downloadImage(
    url: string,
    abortSignal: AbortSignal | undefined,
  ): Promise<Uint8Array> {
    const { value } = await getFromApi({
      url,
      abortSignal,
      failedResponseHandler: createStatusCodeErrorResponseHandler(),
      successfulResponseHandler: createBinaryResponseHandler(),
      fetch: this.config.fetch,
    });
    return value;
  }
}

