import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createBinaryResponseHandler,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  createStatusCodeErrorResponseHandler,
  FetchFunction,
  getFromApi,
  parseProviderOptions,
  postJsonToApi,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtImageModelId } from './pixelart-image-settings';

// ---------------------------------------------------------------------------
// Internal config passed from the provider factory to each model instance
// ---------------------------------------------------------------------------

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// ---------------------------------------------------------------------------
// Provider-options Zod schema (maps to PixelArtImageSettings)
// ---------------------------------------------------------------------------

const pixelArtImageSettingsSchema = z.object({
  size: z.string().optional(),
  style: z.enum(['pixel', 'retro', '8bit']).optional(),
  pixelDensity: z.number().optional(),
});

// ---------------------------------------------------------------------------
// Response / error schemas
// ---------------------------------------------------------------------------

const pixelArtImageSchema = z.object({
  url: z.string(),
  width: z.number().nullish(),
  height: z.number().nullish(),
});

const pixelArtImageResponseSchema = z.object({
  images: z.array(pixelArtImageSchema),
  model: z.string().nullish(),
  created_at: z.string().nullish(),
});

const pixelArtErrorSchema = z.object({
  error: z
    .object({
      message: z.string(),
      code: z.string().optional(),
    })
    .or(z.string()),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: err => {
    if (typeof err.error === 'string') return err.error;
    return err.error.message ?? 'Unknown PixelArt error';
  },
});

// ---------------------------------------------------------------------------
// Image model implementation
// ---------------------------------------------------------------------------

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  private async getArgs({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
  }: Parameters<ImageModelV3['doGenerate']>[0]) {
    const warnings: Array<SharedV3Warning> = [];

    // Parse provider-specific options (pixelart namespace)
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageSettingsSchema,
    });

    // Determine image size: provider option takes precedence, then standard
    // `size` parameter, then nothing (API default).
    const resolvedSize =
      pixelArtOptions?.size ?? size ?? undefined;

    // Aspect ratio is not natively supported; emit a warning if provided
    if (aspectRatio != null && size == null && pixelArtOptions?.size == null) {
      warnings.push({
        type: 'unsupported-setting',
        setting: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio directly. Use the `size` ' +
          'setting (e.g. "512x512") to control image dimensions.',
      });
    }

    const requestBody: Record<string, unknown> = {
